mapper.select:
SELECT B.EQ_CODE, B.DEVICE_CODE, B.DEVICE_TYPE, B.DEVICE_NAME, A.DEVICE_STATUS_ADDR_CODE, B.CFG_CODE, '0' AS WORK_ID FROM MD_DEVICE_STATUS_ADDR A INNER JOIN MD_DEVICE B ON A.CFG_CODE = B.CFG_CODE AND A.EQ_CODE = B.EQ_CODE AND A.DEVICE_CODE = B.DEVICE_CODE WHERE B.CFG_CODE IN
#{cfgCode}
ORDER BY A.DEVICE_STATUS_ADDR_CODE
